using decoder = basic_decoder<feedforge::profile::portable_checked>;

template <class Sink>
  requires sink_for_all_selected_events<Sink>
[[nodiscard]] feedforge::replay_summary replay_binary_file(
    std::span<const std::byte> input, Sink& sink) noexcept {
  decoder message_decoder{};
  feedforge::replay_summary summary{};
  std::size_t position{};

  for (;;) {
    const std::size_t available = input.size() - position;
    if (available == 0U) {
      summary.status = feedforge::replay_status::incomplete;
      summary.bytes_consumed = position;
      return summary;
    }
    if (available == 1U) {
      summary.status = feedforge::replay_status::framing_error;
      summary.bytes_consumed = position;
      summary.error_offset = position;
      summary.framing_error = feedforge::framing_errc::truncated_length_prefix;
      return summary;
    }

    const std::size_t frame_offset = position;
    const auto high = std::to_integer<std::uint16_t>(input[position]);
    const auto low = std::to_integer<std::uint16_t>(input[position + 1U]);
    const auto payload_size = static_cast<std::uint16_t>((high << 8U) | low);

    if (payload_size == 0U) {
      position += 2U;
      if (position != input.size()) {
        summary.status = feedforge::replay_status::framing_error;
        summary.bytes_consumed = position;
        summary.error_offset = position;
        summary.framing_error = feedforge::framing_errc::trailing_data_after_end_marker;
        return summary;
      }
      summary.status = feedforge::replay_status::complete;
      summary.bytes_consumed = position;
      return summary;
    }

    if (static_cast<std::size_t>(payload_size) > available - 2U) {
      summary.status = feedforge::replay_status::framing_error;
      summary.bytes_consumed = position;
      summary.error_offset = frame_offset;
      summary.framing_error = feedforge::framing_errc::truncated_payload;
      return summary;
    }

    const auto payload = input.subspan(position + 2U, payload_size);
    position += 2U + static_cast<std::size_t>(payload_size);
    ++summary.frames_seen;
    const feedforge::decode_outcome outcome = message_decoder.decode_one(payload, sink);
    if (outcome.status == feedforge::decode_status::emitted) {
      ++summary.events_emitted;
      continue;
    }
    if (outcome.status == feedforge::decode_status::known_unselected_skipped) {
      ++summary.known_messages_skipped;
      continue;
    }
    if (outcome.status == feedforge::decode_status::unknown_skipped) {
      ++summary.unknown_messages_skipped;
      continue;
    }
    if (outcome.status == feedforge::decode_status::stopped) {
      ++summary.events_emitted;
      summary.status = feedforge::replay_status::stopped;
      summary.bytes_consumed = position;
      return summary;
    }
    summary.status = feedforge::replay_status::decode_error;
    summary.bytes_consumed = position;
    summary.error_offset = frame_offset + 2U;
    summary.decode_error = outcome;
    return summary;
  }
}

template <class Sink>
  requires sink_for_all_selected_events<Sink>
class chunked_replayer {
 public:
  explicit chunked_replayer(
      std::span<std::byte> scratch, Sink& sink) noexcept
    : cursor_(scratch), sink_(sink) {
    summary_.status = feedforge::replay_status::incomplete;
  }

  chunked_replayer(const chunked_replayer&) = delete;
  chunked_replayer& operator=(const chunked_replayer&) = delete;
  chunked_replayer(chunked_replayer&&) = delete;
  chunked_replayer& operator=(chunked_replayer&&) = delete;

  [[nodiscard]] feedforge::replay_summary push(
      std::span<const std::byte> chunk) noexcept {
    if (terminal_) {
      return summary_;
    }

    std::size_t position{};
    while (position != chunk.size()) {
      const feedforge::chunk_frame_outcome frame =
          cursor_.next(chunk.subspan(position));
      position += frame.input_consumed;
      summary_.bytes_consumed = cursor_.consumed();
      switch (frame.status) {
        case feedforge::chunk_frame_status::frame:
          if (!decode_frame(frame.frame)) {
            return summary_;
          }
          break;
        case feedforge::chunk_frame_status::needs_input:
          return summary_;
        case feedforge::chunk_frame_status::complete:
          summary_.status = feedforge::replay_status::complete;
          terminal_ = true;
          return summary_;
        case feedforge::chunk_frame_status::incomplete:
          summary_.status = feedforge::replay_status::incomplete;
          terminal_ = true;
          return summary_;
        case feedforge::chunk_frame_status::error:
          set_framing_error(frame);
          return summary_;
      }
    }
    return summary_;
  }

  [[nodiscard]] feedforge::replay_summary finish() noexcept {
    if (terminal_) {
      return summary_;
    }
    const feedforge::chunk_frame_outcome frame = cursor_.finish();
    summary_.bytes_consumed = cursor_.consumed();
    switch (frame.status) {
      case feedforge::chunk_frame_status::frame:
        static_cast<void>(decode_frame(frame.frame));
        return summary_;
      case feedforge::chunk_frame_status::needs_input:
        return summary_;
      case feedforge::chunk_frame_status::complete:
        summary_.status = feedforge::replay_status::complete;
        terminal_ = true;
        return summary_;
      case feedforge::chunk_frame_status::incomplete:
        summary_.status = feedforge::replay_status::incomplete;
        terminal_ = true;
        return summary_;
      case feedforge::chunk_frame_status::error:
        set_framing_error(frame);
        return summary_;
    }
    return summary_;
  }

  [[nodiscard]] feedforge::replay_summary summary() const noexcept {
    return summary_;
  }

 private:
  [[nodiscard]] bool decode_frame(
      const feedforge::frame_view& frame) noexcept {
    ++summary_.frames_seen;
    const feedforge::decode_outcome outcome =
        message_decoder_.decode_one(frame.payload, sink_);
    if (outcome.status == feedforge::decode_status::emitted) {
      ++summary_.events_emitted;
      return true;
    }
    if (outcome.status == feedforge::decode_status::known_unselected_skipped) {
      ++summary_.known_messages_skipped;
      return true;
    }
    if (outcome.status == feedforge::decode_status::unknown_skipped) {
      ++summary_.unknown_messages_skipped;
      return true;
    }
    if (outcome.status == feedforge::decode_status::stopped) {
      ++summary_.events_emitted;
      summary_.status = feedforge::replay_status::stopped;
    } else {
      summary_.status = feedforge::replay_status::decode_error;
      summary_.error_offset = frame.file_offset + 2U;
      summary_.decode_error = outcome;
    }
    terminal_ = true;
    return false;
  }

  void set_framing_error(
      const feedforge::chunk_frame_outcome& frame) noexcept {
    summary_.status = feedforge::replay_status::framing_error;
    summary_.error_offset = frame.offset;
    summary_.framing_error = frame.error;
    terminal_ = true;
  }

  feedforge::chunked_binary_file_cursor cursor_;
  decoder message_decoder_{};
  Sink& sink_;
  feedforge::replay_summary summary_{};
  bool terminal_{};
};

